&lt;p&gt;&lt;strong&gt;&lt;span data-contrast=&quot;none&quot;&gt;&lt;span data-ccp-parastyle=&quot;heading 2&quot;&gt;How the&amp;nbsp;&lt;/span&gt;&lt;span data-ccp-parastyle=&quot;heading 2&quot;&gt;Programme&lt;/span&gt;&lt;span data-ccp-parastyle=&quot;heading 2&quot;&gt;&amp;nbsp;Works&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;span data-ccp-props=&quot;{&amp;quot;335559738&amp;quot;:280,&amp;quot;335559739&amp;quot;:160}&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;
